               onChange={e => setSearchTerm(e.target.value)}
               placeholder="搜索姓名、编号、备注..."
               className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm bg-gray-50 focus:bg-white"
             />
