                      <p>• <span className="font-bold">打钩识别</span>：单元格填 1、√、v 均视为全天报名。</p>
                      <p>• <span className="font-bold">时段识别</span>：单元格含 "上午" 或 "下午" 会自动区分状态。</p>
                      <p>• <span className="font-bold">自动编号</span>：若第一列不是编号（如是姓名），系统会自动生成。</p>
                   </div>

                   <div>
                      <textarea 
                        value={importText}
                        onChange={e => setImportText(e.target.value)}
                        placeholder={`姓名,出生日期,年龄,现居住地址,备注,"5.1"\n张三,2000.1.1,24,广州市,无,1\n李四,2002.2.2,22,深圳市,无,上午`}
                        className="w-full h-64 border border-gray-300 rounded-lg p-3 font-mono text-sm outline-none focus:ring-2 focus:ring-indigo-500 resize-none whitespace-pre"
                      />
                   </div>

                   <div className="flex justify-between items-center">
                      <button onClick={() => fileInputRef.current?.click()} className="text-sm text-gray-700 bg-white border border-gray-300 hover:bg-gray-50 px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm">
                         <FileSpreadsheet size={16} /> 选择文件 (.csv / .txt)
                      </button>
                      <input type="file" ref={fileInputRef} className="hidden" accept=".csv,.txt" onChange={handleFileUpload} />
                   </div>
                </div>

                <div className="p-6 border-t border-gray-100 flex justify-end gap-3 rounded-b-2xl bg-gray-50 shrink-0">
                   <button onClick={() => setIsImportModalOpen(false)} className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-white transition-colors">取消</button>
                   <button 
                     onClick={handleImport} 
                     disabled={!importText.trim()}
                     className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 shadow-sm transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                   >
                     解析并导入
                   </button>
                </div>
             </div>
          </div>
       )}
    </div>
  );
};

