import React, { useState } from 'react';
import { Staff, RegistrationRecord } from '../types';
import { Star, Award, Briefcase, Phone, User, Edit3, Trash2, Search, Calendar, MapPin, UserCheck, Shield } from 'lucide-react';

interface TalentPoolProps {
  staffList: Staff[]; // Internal employees
  registrationList: RegistrationRecord[]; // External candidates
  onUpdateStaff: (staff: Staff) => void;
  onUpdateRegistration: (records: RegistrationRecord[]) => void;
}

const TalentPool: React.FC<TalentPoolProps> = ({ 
  staffList, 
  registrationList, 
  onUpdateStaff, 
  onUpdateRegistration 
}) => {
  const [activeTab, setActiveTab] = useState<'INTERNAL' | 'EXTERNAL'>('INTERNAL');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editNote, setEditNote] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // 1. Internal Elite: Active Staff with isTalent=true
  const internalTalents = staffList.filter(s => s.status === 'ACTIVE' && s.isTalent);

  // 2. External Reserve: Registration Records with isTalent=true
  const externalTalents = registrationList.filter(r => r.isTalent);

  const displayedList = activeTab === 'INTERNAL' ? internalTalents : externalTalents;

  const filteredList = displayedList.filter((item: any) => {
    const searchLower = searchTerm.toLowerCase();
    return (
      item.name.toLowerCase().includes(searchLower) ||
      (item.phone && item.phone.includes(searchLower)) ||
      (item.talentNotes && item.talentNotes.toLowerCase().includes(searchLower)) || 
      (item.managementNotes && item.managementNotes.toLowerCase().includes(searchLower)) ||
      (item.registrationNumber && item.registrationNumber.includes(searchLower))
    );
  });

  const handleRemoveInternal = (staff: Staff) => {
    if (confirm(`确定将 ${staff.name} 移出内部精英库吗？`)) {
      onUpdateStaff({ ...staff, isTalent: false });
    }
  };

  const handleRemoveExternal = (record: RegistrationRecord) => {
    if (confirm(`确定将 ${record.name} 移出外部人才储备吗？`)) {
      const updatedList = registrationList.map(r => r.id === record.id ? { ...r, isTalent: false } : r);
      onUpdateRegistration(updatedList);
    }
  };

  const startEdit = (item: any) => {
    setEditingId(item.id);
    // For Internal: talentNotes. For External: managementNotes (as admin note)
    setEditNote(activeTab === 'INTERNAL' ? item.talentNotes || '' : item.managementNotes || '');
  };

