      id: crypto.randomUUID(),
      staffId,
      staffName: staff.name,
      ticketNumber: `A-${String(queue.length + 1).padStart(3, '0')}`,
      status: 'WAITING',
      checkInTime: new Date().toISOString()
    };
    setQueue(prev => [...prev, newTicket]);
  };

