                    // Logic: Explicit text overrides symbols
                    if (val.includes('上午') || val.includes('am')) availMap[h.label] = 'AM';
                    else if (val.includes('下午') || val.includes('pm')) availMap[h.label] = 'PM';
                    else if (val.includes('全天') || val.includes('full')) availMap[h.label] = 'FULL';
                    else if (['1', '√', 'v', '✓', 'true', 'yes', '是', '有'].some(k => val === k || val.startsWith(k))) {
                        // Default to FULL if mapped with a checkmark
                        availMap[h.label] = 'FULL';
                    }
                }
            });
        }

        newRecords.push({
            id: crypto.randomUUID(),
            registrationNumber: number,
            name: name,
            dob: dob,
            age: age,
            address: address,
            notes: notes,
            managementNotes: '', // Initialize empty management notes
            availability: JSON.stringify(availMap),
            submissionTime: new Date().toISOString(),
            isTalent: false,
        });
    }

    if (newRecords.length > 0) {
        onUpdateRecords([...records, ...newRecords]);
        showToast(`成功导入 ${newRecords.length} 条数据`);
        setImportText('');
        setIsImportModalOpen(false);
    } else {
        showToast('未解析到有效数据，请检查格式', 'error');
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      setImportText(evt.target?.result as string);
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const requestDelete = (id: string) => {
    setConfirmModal({
      isOpen: true,
      type: 'DELETE_ONE',
      targetId: id,
      title: '删除记录',
      message: '确定要删除这条报名记录吗？'
    });
