    let currentCell = '';
    let insideQuote = false;
    // Normalize line endings
    const normalizedText = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    for (let i = 0; i < normalizedText.length; i++) {
      const char = normalizedText[i];
      const nextChar = normalizedText[i + 1];

      if (char === '"') {
        if (insideQuote && nextChar === '"') {
          currentCell += '"';
          i++;
        } else {
          insideQuote = !insideQuote;
        }
      } else if ((char === ',' || char === '\t') && !insideQuote) { // Accept tab or comma
        currentRow.push(currentCell.trim());
        currentCell = '';
      } else if (char === '\n' && !insideQuote) {
        currentRow.push(currentCell.trim());
        if (currentRow.length > 0 && (currentRow.length > 1 || currentRow[0] !== '')) {
           rows.push(currentRow);
        }
        currentRow = [];
        currentCell = '';
      } else {
        currentCell += char;
      }
    }
    if (currentCell || currentRow.length > 0) {
      currentRow.push(currentCell.trim());
      rows.push(currentRow);
    }
    return rows;
  };

  const handleImport = () => {
    if (!importText.trim()) {
      showToast('请输入或粘贴数据', 'error');
      return;
    }

    const rows = parseCSV(importText);
    if (rows.length === 0) return;

    // Header processing
    const headerRow = rows[0];
    // Clean headers: remove quotes, collapse newlines to spaces for consistency
    const cleanHeader = headerRow.map(h => h.replace(/^"|"$/g, '').replace(/\n/g, '').trim());

    const hasHeader = cleanHeader.some(p => p.includes('姓名') || p.includes('生日') || p.includes('出生日期') || p.includes('备注'));
    const startRowIndex = hasHeader ? 1 : 0;

    let colMap = {
        number: -1,
        name: 0,
        dob: 1,
        age: 2,
        address: 3,
        notes: 4,
    };

    if (hasHeader) {
        colMap = {
            number: cleanHeader.findIndex(p => p.includes('编号')),
            name: cleanHeader.findIndex(p => p.includes('姓名')),
            dob: cleanHeader.findIndex(p => p.includes('出生日期') || p.includes('生日')),
            age: cleanHeader.findIndex(p => p.includes('年龄')),
            address: cleanHeader.findIndex(p => p.includes('地址') || p.includes('现居住')),
            notes: cleanHeader.findIndex(p => p.includes('备注')),
        };
    }

    // Identify Dynamic Date Columns
    // Anything that is not a standard column and is likely after the notes column
    const dynamicHeaders: { index: number, label: string }[] = [];
    if (hasHeader) {
        const standardIndices = Object.values(colMap).filter(i => i !== -1);
        const maxStandard = Math.max(...standardIndices, 4); // assume at least col 4 is standard

        cleanHeader.forEach((part, index) => {
            if (!standardIndices.includes(index) && index > maxStandard && part) {
                // Shorten label for display if possible (e.g. remove 【全天】 suffix if redundant)
                // But keep unique. Let's just use the cleaned part.
                dynamicHeaders.push({ index, label: part });
            }
        });
    }

    const existingNumbers = records.map(r => parseInt(r.registrationNumber)).filter(n => !isNaN(n));
    let nextAutoNumber = existingNumbers.length > 0 ? Math.max(...existingNumbers) + 1 : 1;

    const newRecords: RegistrationRecord[] = [];

    for (let i = startRowIndex; i < rows.length; i++) {
        const row = rows[i];
        if (row.length < 2) continue;

        // Extract Basic Info
        let number = colMap.number !== -1 ? row[colMap.number] : '';
        const name = colMap.name !== -1 ? row[colMap.name] : '';

        if (!name) continue; // Name is mandatory

        if (!number) {
            number = String(nextAutoNumber++);
        }

        const dob = colMap.dob !== -1 ? row[colMap.dob] : '';
        const age = colMap.age !== -1 ? row[colMap.age] : '';
        const address = colMap.address !== -1 ? row[colMap.address] : '';
        const notes = colMap.notes !== -1 ? row[colMap.notes] : '';

        // Extract Availability
        const availMap: Record<string, AvailabilityState> = {};

        if (hasHeader) {
            dynamicHeaders.forEach(h => {
                const val = row[h.index] ? row[h.index].trim().toLowerCase() : '';
                if (val) {
                    // Logic: Explicit text overrides symbols
                    if (val.includes('上午') || val.includes('am')) availMap[h.label] = 'AM';
                    else if (val.includes('下午') || val.includes('pm')) availMap[h.label] = 'PM';
                    else if (val.includes('全天') || val.includes('full')) availMap[h.label] = 'FULL';
                    else if (['1', '√', 'v', '✓', 'true', 'yes', '是', '有'].some(k => val === k || val.startsWith(k))) {
                        // Default to FULL if mapped with a checkmark
                        availMap[h.label] = 'FULL';
                    }
                }
            });
        }

        newRecords.push({
            id: crypto.randomUUID(),
            registrationNumber: number,
            name: name,
            dob: dob,
            age: age,
            address: address,
            notes: notes,
            managementNotes: '', // Initialize empty management notes
            availability: JSON.stringify(availMap),
            submissionTime: new Date().toISOString(),
            isTalent: false,
        });
    }

    if (newRecords.length > 0) {
        onUpdateRecords([...records, ...newRecords]);
        showToast(`成功导入 ${newRecords.length} 条数据`);
        setImportText('');
        setIsImportModalOpen(false);
    } else {
        showToast('未解析到有效数据，请检查格式', 'error');
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      setImportText(evt.target?.result as string);
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const requestDelete = (id: string) => {
    setConfirmModal({
      isOpen: true,
      type: 'DELETE_ONE',
      targetId: id,
      title: '删除记录',
      message: '确定要删除这条报名记录吗？'
    });
  };

  const executeAction = () => {
    if (confirmModal.type === 'DELETE_ONE' && confirmModal.targetId) {
       onUpdateRecords(records.filter(r => r.id !== confirmModal.targetId));
       showToast('记录已删除', 'success');
    } else if (confirmModal.type === 'CLEAR_ALL') {
       onUpdateRecords([]);
       showToast('列表已清空', 'success');
    }
    setConfirmModal({ ...confirmModal, isOpen: false });
  };

  const cycleAvailability = (recordId: string, header: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;

    const map = getAvailabilityMap(record);
    const currentState = map[header] || 'EMPTY';

    // Cycle: EMPTY -> FULL -> AM -> PM -> EMPTY
    let nextState: AvailabilityState = 'EMPTY';
    if (currentState === 'EMPTY') nextState = 'FULL';
    else if (currentState === 'FULL') nextState = 'AM';
    else if (currentState === 'AM') nextState = 'PM';
    else if (currentState === 'PM') nextState = 'EMPTY';

    if (nextState === 'EMPTY') {
        delete map[header];
    } else {
        map[header] = nextState;
    }

    const updatedRecord = { ...record, availability: JSON.stringify(map) };
    onUpdateRecords(records.map(r => r.id === recordId ? updatedRecord : r));
  };

  const toggleTalent = (recordId: string) => {
    const updated = records.map(r => r.id === recordId ? { ...r, isTalent: !r.isTalent } : r);
    onUpdateRecords(updated);
  };

  const openNoteModal = (record: RegistrationRecord) => {
    setEditingNoteRecord(record);
    setEditingNoteContent(record.notes || '');
    setIsNoteModalOpen(true);
  };

  const saveNote = () => {
    if (editingNoteRecord) {
        const updated = records.map(r => r.id === editingNoteRecord.id ? { ...r, notes: editingNoteContent } : r);
        onUpdateRecords(updated);
        showToast('备注已更新');
        setIsNoteModalOpen(false);
        setEditingNoteRecord(null);
    }
  };

  // Update Management Notes directly
  const updateManagementNote = (id: string, value: string) => {
    const updated = records.map(r => r.id === id ? { ...r, managementNotes: value } : r);
    onUpdateRecords(updated);
  };

  const filteredRecords = records.filter(r => 
    r.name.includes(searchTerm) || 
    r.registrationNumber.includes(searchTerm) ||
    (r.notes && r.notes.includes(searchTerm)) ||
    (r.managementNotes && r.managementNotes.includes(searchTerm))
  );

  return (
    <div className="space-y-6 animate-fade-in pb-24 h-[calc(100vh-8rem)] flex flex-col relative">
       {/* Header */}
       <div className="flex justify-between items-center shrink-0">
          <div>
            <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
              <FileText className="text-indigo-600" /> STAFF报名管理
            </h1>
            <p className="text-gray-500 text-sm">导入并管理报名人员电子名册</p>
          </div>
          <div className="flex gap-2">
             <button 
               onClick={() => setConfirmModal({isOpen: true, type: 'CLEAR_ALL', title: '清空列表', message: '确定要清空所有报名数据吗？'})}
               disabled={records.length === 0}
               className="px-4 py-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg text-sm font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
             >
               清空列表
             </button>
             <button 
               onClick={() => setIsImportModalOpen(true)}
               className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 shadow-sm flex items-center gap-2 transition-colors"
             >
               <UploadCloud size={16} /> 导入Excel/CSV
             </button>
          </div>
       </div>

       {/* Search & Stats */}
       <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex justify-between items-center shrink-0">
          <div className="relative w-full max-w-md">
             <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
             <input 
               type="text" 
               value={searchTerm}
               onChange={e => setSearchTerm(e.target.value)}
               placeholder="搜索姓名、编号、备注..."
               className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm bg-gray-50 focus:bg-white"
             />
          </div>
          <div className="text-sm text-gray-500">
             共 <span className="font-bold text-gray-900">{records.length}</span> 条记录
          </div>
       </div>

       {/* Data Table */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-100 flex-1 overflow-hidden flex flex-col min-h-0 relative">
          <div className="overflow-y-auto flex-1 custom-scrollbar">
             <table className="w-full text-left border-collapse">
                {/* Fixed Header with higher Z-Index and Solid Background to prevent bleed-through */}
                <thead className="bg-gray-50 sticky top-0 z-20 shadow-sm border-b border-gray-200">
                   <tr>
                      <th className="px-3 py-4 w-12 text-center">
                         <Star size={16} className="text-gray-400 mx-auto" />
                      </th>
                      <th className="px-3 py-4 text-xs font-bold text-gray-500 uppercase text-center w-16">编号</th>
                      <th className="px-3 py-4 text-xs font-bold text-gray-500 uppercase text-center w-24">姓名</th>
                      <th className="px-3 py-4 text-xs font-bold text-gray-500 uppercase text-center w-56">基本信息</th>
                      <th className="px-3 py-4 text-xs font-bold text-gray-500 uppercase text-center w-48">备注</th>
                      <th className="px-3 py-4 text-xs font-bold text-indigo-600 uppercase text-center w-48 bg-indigo-50/30">
                         <div className="flex items-center justify-center gap-1"><Shield size={12} /> 后台备注</div>
                      </th>
                      <th className="px-3 py-4 text-xs font-bold text-gray-500 uppercase text-center min-w-[300px]">
                         可参加时间
                      </th>
                      <th className="px-3 py-4 text-xs font-bold text-gray-500 uppercase text-center w-16">操作</th>
                   </tr>
                </thead>
                <tbody className="divide-y divide-gray-100 bg-white">
                   {filteredRecords.length > 0 ? (
                      filteredRecords.map(record => {
                        const availMap = getAvailabilityMap(record);
                        return (
                         <tr key={record.id} className="hover:bg-gray-50 transition-colors group">
                            <td className="px-3 py-4 text-center align-middle">
                                <button 
                                  onClick={() => toggleTalent(record.id)}
                                  className={`p-1.5 rounded-full hover:bg-yellow-50 transition-colors ${record.isTalent ? 'text-yellow-500' : 'text-gray-200 hover:text-yellow-400'}`}
                                >
                                   <Star size={18} className={record.isTalent ? 'fill-current' : ''} />
                                </button>
                            </td>
                            <td className="px-3 py-4 text-center align-middle">
                                <span className="font-mono text-xs text-gray-500 font-bold bg-gray-100 px-1.5 py-0.5 rounded">{record.registrationNumber}</span>
                            </td>
                            <td className="px-3 py-4 text-center align-middle">
                                <span className="font-bold text-gray-800 text-sm">{record.name}</span>
                            </td>
                            <td className="px-3 py-4 align-middle">
                               <div className="flex flex-col items-center gap-1.5">
                                   <div className="flex flex-wrap justify-center gap-1">
                                       {record.dob && <span className="flex items-center gap-1 text-[10px] bg-blue-50 text-blue-700 px-1.5 py-0.5 rounded border border-blue-100 whitespace-nowrap"><Calendar size={10} /> {record.dob}</span>}
                                       {record.age && <span className="flex items-center gap-1 text-[10px] bg-gray-100 text-gray-600 px-1.5 py-0.5 rounded border border-gray-200 whitespace-nowrap"><User size={10} /> {record.age}岁</span>}
                                   </div>
                                   {record.address && (
                                       <div className="flex items-center justify-center gap-1 text-[10px] text-gray-500 max-w-[200px] text-center" title={record.address}>
                                            <MapPin size={10} className="text-gray-400 shrink-0" />
                                            <span className="truncate">{record.address}</span>
                                       </div>
                                   )}
                                   {(!record.dob && !record.age && !record.address) && <span className="text-gray-300 text-xs">-</span>}
                               </div>
                            </td>
                            <td className="px-3 py-4 align-middle text-center relative group/note">
                               <div className="inline-flex items-center gap-1 max-w-[180px] mx-auto cursor-pointer p-1 rounded hover:bg-gray-100 transition-colors" onClick={() => openNoteModal(record)}>
                                   <span className={`text-xs ${record.notes ? 'text-gray-600' : 'text-gray-300 italic'} line-clamp-2`}>
                                      {record.notes || '点击添加备注...'}
                                   </span>
                                   <Edit3 size={12} className="text-gray-400 opacity-0 group-hover/note:opacity-100 transition-opacity shrink-0" />
                               </div>
                            </td>
                            <td className="px-3 py-4 align-middle text-center bg-indigo-50/10">
                               <input 
                                 type="text" 
                                 className="w-full bg-transparent border-b border-transparent focus:border-indigo-400 text-xs text-center outline-none py-1 text-indigo-700 placeholder-indigo-200"
                                 placeholder="点击输入..."
                                 value={record.managementNotes || ''}
                                 onChange={(e) => updateManagementNote(record.id, e.target.value)}
                               />
                            </td>
                            <td className="px-3 py-3 align-middle">
                                <div className="grid grid-cols-3 gap-2 justify-items-center mx-auto w-fit">
                                    {allHeaders.length > 0 ? (
                                        allHeaders.map(header => {
                                            const state: AvailabilityState = availMap[header] || 'EMPTY';
                                            const config = STATE_CONFIG[state];
                                            // Format header date nicely (e.g., "5.1" from "5.1\n【全天】")
                                            const shortHeader = header.match(/^\d+(\.\d+)?/)?.[0] || header.substring(0, 4);

                                            return (
                                                <button
                                                    key={header}
                                                    onClick={() => cycleAvailability(record.id, header)}
                                                    className={`
                                                        flex flex-col items-center justify-center
                                                        w-14 h-11 rounded-lg border transition-all cursor-pointer select-none
                                                        ${config.color} hover:brightness-95 active:scale-95
                                                    `}
                                                    title={`${header}: 点击切换状态`}
                                                >
                                                    <span className="text-[10px] font-bold opacity-70 leading-none mb-1">{shortHeader}</span>
                                                    <div className="flex items-center gap-1">
                                                        {config.icon}
                                                        <span className="text-[10px] font-bold">{config.shortLabel}</span>
                                                    </div>
                                                </button>
                                            );
                                        })
                                    ) : (
                                        <span className="text-xs text-gray-300 italic col-span-3">暂无排班列</span>
                                    )}
                                </div>
                            </td>
                            <td className="px-3 py-4 text-center align-middle">
                               <button 
                                 onClick={() => requestDelete(record.id)} 
                                 className="text-gray-300 hover:text-red-600 transition-colors p-1.5 rounded-lg hover:bg-red-50" 
                                 title="删除"
                               >
                                  <Trash2 size={16} />
                               </button>
                            </td>
                         </tr>
                        );
                      })
                   ) : (
                      <tr>
                         <td colSpan={8} className="px-6 py-20 text-center text-gray-400">
                            <div className="flex flex-col items-center">
                               <FileSpreadsheet size={48} className="mb-4 opacity-20" />
                               <p>暂无数据</p>
                               <p className="text-xs mt-1">请点击右上角导入 Excel 数据</p>
                            </div>
                         </td>
                      </tr>
                   )}
                </tbody>
             </table>
          </div>
       </div>

       {/* Confirmation Modal */}
       {confirmModal.isOpen && (
          <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in duration-200">
                <div className="p-6 text-center">
                   <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600">
                      <AlertTriangle size={24} />
                   </div>
                   <h3 className="text-lg font-bold text-gray-900 mb-2">{confirmModal.title}</h3>
                   <p className="text-sm text-gray-500 mb-6">{confirmModal.message}</p>

                   <div className="flex gap-3">
                      <button 
                        onClick={() => setConfirmModal({ ...confirmModal, isOpen: false })}
                        className="flex-1 py-2.5 border border-gray-300 rounded-lg text-gray-700 font-medium hover:bg-gray-50 transition-colors"
                      >
                        取消
                      </button>
                      <button 
                        onClick={executeAction}
                        className="flex-1 py-2.5 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 shadow-md shadow-red-200 transition-colors"
                      >
                        确认执行
                      </button>
                   </div>
                </div>
             </div>
          </div>
       )}

       {/* Edit Note Modal */}
       {isNoteModalOpen && (
          <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4">
             <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in duration-200">
                <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                   <h3 className="font-bold text-gray-800">编辑备注</h3>
                   <button onClick={() => setIsNoteModalOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
                </div>
                <div className="p-6">
                   <textarea 
                     className="w-full h-32 border border-gray-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                     value={editingNoteContent}
                     onChange={(e) => setEditingNoteContent(e.target.value)}
                     placeholder="请输入备注信息..."
                     autoFocus
                   />
                </div>
                <div className="px-6 py-4 border-t border-gray-100 flex justify-end gap-3 bg-gray-50">
                   <button onClick={() => setIsNoteModalOpen(false)} className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-white text-sm">取消</button>
                   <button onClick={saveNote} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm">保存</button>
                </div>
             </div>
          </div>
       )}

       {/* Toast Notification */}
       {toast && (
          <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-4 py-3 rounded-xl shadow-2xl text-white text-sm font-medium animate-in slide-in-from-bottom-5 fade-in duration-300 z-50 flex items-center gap-2 ${toast.type === 'success' ? 'bg-gray-800' : 'bg-red-500'}`}>
             {toast.type === 'success' ? <CheckCircle2 size={18} className="text-green-400" /> : <AlertCircle size={18} className="text-white" />}
             {toast.message}
          </div>
       )}

       {/* Import Modal */}
       {isImportModalOpen && (
          <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-2xl shadow-xl w-full max-w-3xl flex flex-col max-h-[90vh] animate-in zoom-in duration-200">
                <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 rounded-t-2xl shrink-0">
                   <h3 className="font-bold text-gray-800 flex items-center gap-2">
                      <UploadCloud size={20} /> 批量导入
                   </h3>
                   <button onClick={() => setIsImportModalOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
                </div>

                <div className="p-6 space-y-4 flex-1 overflow-y-auto">
                   <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100 text-sm text-indigo-800">
                      <p className="font-bold mb-2">Excel/TXT 格式适配说明：</p>
                      <p>请直接复制 Excel 中的数据区域并粘贴（建议包含表头）。</p>
                      <p>• <span className="font-bold">打钩识别</span>：单元格填 1、√、v 均视为全天报名。</p>
                      <p>• <span className="font-bold">时段识别</span>：单元格含 "上午" 或 "下午" 会自动区分状态。</p>
                      <p>• <span className="font-bold">自动编号</span>：若第一列不是编号（如是姓名），系统会自动生成。</p>
                   </div>

                   <div>
                      <textarea 
                        value={importText}
                        onChange={e => setImportText(e.target.value)}
                        placeholder={`姓名,出生日期,年龄,现居住地址,备注,"5.1"\n张三,2000.1.1,24,广州市,无,1\n李四,2002.2.2,22,深圳市,无,上午`}
                        className="w-full h-64 border border-gray-300 rounded-lg p-3 font-mono text-sm outline-none focus:ring-2 focus:ring-indigo-500 resize-none whitespace-pre"
                      />
                   </div>

                   <div className="flex justify-between items-center">
                      <button onClick={() => fileInputRef.current?.click()} className="text-sm text-gray-700 bg-white border border-gray-300 hover:bg-gray-50 px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm">
                         <FileSpreadsheet size={16} /> 选择文件 (.csv / .txt)
                      </button>
                      <input type="file" ref={fileInputRef} className="hidden" accept=".csv,.txt" onChange={handleFileUpload} />
                   </div>
                </div>

                <div className="p-6 border-t border-gray-100 flex justify-end gap-3 rounded-b-2xl bg-gray-50 shrink-0">
                   <button onClick={() => setIsImportModalOpen(false)} className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-white transition-colors">取消</button>
                   <button 
                     onClick={handleImport} 
                     disabled={!importText.trim()}
                     className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 shadow-sm transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                   >
                     解析并导入
                   </button>
                </div>
             </div>
          </div>
       )}
    </div>
  );
};

export default StaffRegistration;
